const orders = [{cid: 1, total: 100}, {cid: 1, total: 200}, {cid: 2, total: 150}];
const avg = orders.reduce((acc, o) => {
  acc[o.cid] = (acc[o.cid] || 0) + o.total;
  return acc;
}, {});

from itertools import groupby
orders = [(1, 100), (1, 200), (2, 150)]
avg = {k: sum(v for _, v in g) / len(list(g)) for k, g in groupby(sorted(orders), key=lambda x: x[0])}
